#!/usr/bin/env python3
# board — a Now / This week / Waiting / Done board, replayed from the log. Folds
# task.captured (a task, id = its seq, starts in "now") and task.moved (id, lane)
# into lanes, and renders each as a card with one-click move forms and a capture
# box. Bare semantic HTML using the kernel class vocabulary; the kernel themes it.
import sys, json
from html import escape

LANES = [("now", "Now"), ("this_week", "This week"), ("waiting", "Waiting"), ("done", "Done")]
tasks, order = {}, []
for line in sys.stdin:
    line = line.strip()
    if not line:
        continue
    try:
        e = json.loads(line)
    except Exception:
        continue
    n = e.get("name"); p = e.get("payload", {}) or {}
    if n == "task.captured":
        sid = e.get("seq")
        tasks[sid] = {"text": p.get("text", ""), "lane": "now",
                      "at": (e.get("occurred_at", "") or "")[:16].replace("T", " ")}
        order.append(sid)
    elif n == "task.moved":
        t = p.get("task")
        try:
            t = int(t)
        except (ValueError, TypeError):
            pass
        if t in tasks:
            tasks[t]["lane"] = p.get("lane", "now")

by_lane = {k: [] for k, _ in LANES}
for sid in order:
    t = tasks[sid]
    by_lane.get(t["lane"], by_lane["now"]).append((sid, t))

print("<!DOCTYPE html>")
print("<html><head><meta charset='utf-8'><title>board</title></head><body>")
print("<h1>board</h1>")
print("<form method='post' action='/run/capture'>"
      "<input name='text' placeholder='capture a task and press enter...'>"
      "<button>capture</button></form>")
active = sum(1 for sid in order if tasks[sid]["lane"] != "done")
print("<p class='muted'>%d open · %d done</p>" % (active, len(by_lane["done"])))

for key, label in LANES:
    items = by_lane[key]
    print("<h2>%s <span class='muted'>(%d)</span></h2>" % (escape(label), len(items)))
    if not items:
        print("<p class='muted'>—</p>")
        continue
    for sid, t in items:
        print("<div class='card'>")
        if key == "done":
            print("<div class='muted'>%s</div>" % escape(t["text"]))
        else:
            print("<div>%s</div>" % escape(t["text"]))
        print("<div class='row'>")
        for dk, dl in LANES:
            if dk == key:
                continue
            btn = "✓ Done" if dk == "done" else dl
            sec = "" if dk == "done" else " class='secondary'"
            print("<form method='post' action='/run/move'>"
                  "<input type='hidden' name='task' value='%s'>"
                  "<input type='hidden' name='lane' value='%s'>"
                  "<button%s>%s</button></form>" % (sid, dk, sec, escape(btn)))
        print("</div>")
        print("<div class='muted'>#%s · %s</div>" % (sid, escape(t["at"])))
        print("</div>")
print("</body></html>")

